/** Generated by Trae Work */
/** GuardYan Dashboard - Medication Schedule Component */

(function() {
  const WEEK_DAYS = ['周一','周二','周三','周四','周五','周六','周日'];

  function renderWeekCalendar(containerId, elderId) {
    const container = document.getElementById(containerId);
    if (!container) return;

    const meds = gyStore.getMedications(elderId);
    const now = new Date();
    const startOfWeek = new Date(now);
    startOfWeek.setDate(now.getDate() - (now.getDay() + 6) % 7); // Monday
    startOfWeek.setHours(0,0,0,0);

    let html = '<div class="week-grid">';
    for (let i = 0; i < 7; i++) {
      const d = new Date(startOfWeek.getTime() + i * 86400000);
      const key = GYUtils.formatDateKey(d);
      const isToday = d.toDateString() === now.toDateString();
      html += `<div class="week-header">${WEEK_DAYS[i]}${isToday ? '<br><small>(今天)</small>' : ''}</div>`;
    }

    for (let i = 0; i < 7; i++) {
      const d = new Date(startOfWeek.getTime() + i * 86400000);
      const key = GYUtils.formatDateKey(d);
      const dayMeds = meds.filter(m => m.records && m.records[key]);
      const allTaken = dayMeds.length > 0 && dayMeds.every(m => m.records[key].taken);
      const somePending = dayMeds.some(m => !m.records[key].taken);

      let cls = 'week-day';
      if (dayMeds.length === 0) cls += ' skip';
      else if (allTaken) cls += ' taken';
      else cls += ' missed';

      let inner = '';
      if (dayMeds.length === 0) {
        inner = '<div style="color:var(--muted);font-size:0.75rem;">无用药</div>';
      } else {
        inner = dayMeds.map(m => {
          const rec = m.records[key];
          const taken = rec && rec.taken;
          return `
            <div class="week-day-drug">${taken ? '✅' : '❌'} ${m.drugName}</div>
            <div class="week-day-dose">${m.dosage}</div>
            <div class="week-day-time">${m.time}</div>
          `;
        }).join('');
      }

      html += `<div class="${cls}">${inner}</div>`;
    }
    html += '</div>';
    container.innerHTML = html;
  }

  function renderMedRules(containerId, elderId) {
    const container = document.getElementById(containerId);
    if (!container) return;

    const meds = gyStore.getMedications(elderId);

    let html = `
      <div class="card" style="margin-bottom:1rem;">
        <div class="card-title"><svg class="icon" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round"><line x1="12" y1="5" x2="12" y2="19"/><line x1="5" y1="12" x2="19" y2="12"/></svg> 添加用药规则</div>
        <div class="form-row">
          <div class="form-group">
            <label class="form-label">药品名称</label>
            <input type="text" class="form-input" id="new-med-name" placeholder="如：氨氯地平片">
          </div>
          <div class="form-group">
            <label class="form-label">剂量</label>
            <input type="text" class="form-input" id="new-med-dose" placeholder="如：5mg">
          </div>
          <div class="form-group">
            <label class="form-label">服用时间</label>
            <input type="time" class="form-input" id="new-med-time" value="08:00">
          </div>
        </div>
        <div class="form-row" style="grid-template-columns: 1fr 1fr; margin-top:0.5rem;">
          <div class="form-group">
            <label class="form-label">重复规则</label>
            <select class="form-select" id="new-med-repeat">
              <option value="daily">每日</option>
              <option value="alternate">隔天</option>
              <option value="custom">自定义</option>
            </select>
          </div>
          <div class="form-group" style="display:flex;align-items:flex-end;">
            <button class="btn btn-primary" id="btn-add-med" style="width:100%;">添加用药</button>
          </div>
        </div>
      </div>
    `;

    if (meds.length === 0) {
      html += '<div class="empty-state">暂无用药规则</div>';
    } else {
      html += '<div class="table-wrap"><table class="data-table"><thead><tr><th>药品</th><th>剂量</th><th>时间</th><th>重复</th><th>操作</th></tr></thead><tbody>';
      html += meds.map(m => `
        <tr>
          <td>${m.drugName}</td>
          <td>${m.dosage}</td>
          <td>${m.time}</td>
          <td>${{daily:'每日',alternate:'隔天',custom:'自定义'}[m.repeatRule]}</td>
          <td>
            <button class="btn btn-ghost btn-sm" data-del-med="${m.id}"><svg class="icon" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round"><polyline points="3 6 5 6 21 6"/><path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"/></svg> 删除</button>
          </td>
        </tr>
      `).join('');
      html += '</tbody></table></div>';
    }

    container.innerHTML = html;

    // Bind add
    document.getElementById('btn-add-med')?.addEventListener('click', () => {
      const name = document.getElementById('new-med-name').value.trim();
      const dose = document.getElementById('new-med-dose').value.trim();
      const time = document.getElementById('new-med-time').value;
      const repeat = document.getElementById('new-med-repeat').value;
      if (!name || !dose || !time) {
        showToast('请填写完整信息', 'error');
        return;
      }
      gyStore.addMedication({
        elderId: elderId, drugName: name, dosage: dose,
        time: time, repeatRule: repeat
      });
      showToast('用药规则已添加', 'success');
      renderMedRules(containerId, elderId);
      renderWeekCalendar('week-calendar', elderId);
    });

    // Bind delete
    container.querySelectorAll('[data-del-med]').forEach(btn => {
      btn.addEventListener('click', () => {
        gyStore.deleteMedication(btn.dataset.delMed);
        showToast('用药规则已删除', 'success');
        renderMedRules(containerId, elderId);
        renderWeekCalendar('week-calendar', elderId);
      });
    });
  }

  window.MedSchedule = { renderWeek: renderWeekCalendar, renderRules: renderMedRules };
})();
